import { describe, expect, test } from '@a0n/gnosis/test';

import {
  AEON,
  MINUTES_PER_HOUR,
  PHI,
  PHI_APERIODIC_ROTATION_STEP,
  normalizeUnitFrac,
  phiRotationState,
  phaseFromPhiTheta,
  tickPhi,
  tickPhiGated,
  phaseOfNatTick,
  phaseOfNatTickAddMinutesPerHourMul,
  phaseOfNatTickAddAeonMul,
  tick,
  tickIterate,
  tickIterateAeon,
  minutesPerHourModAeonZero,
} from './clock';

describe('gnosis-time clock', () => {
  test('tick wraps twelve phases', () => {
    expect(tick(AEON - 1)).toBe(0);
    expect(tick(0)).toBe(1);
  });

  test('tickIterate agrees with repeated tick', () => {
    let t = 3;
    for (let i = 0; i < 17; i++) {
      t = tick(t);
    }
    expect(tickIterate(17, 3)).toBe(t);
  });

  test('tickIterateAeon is identity on valid phases', () => {
    for (let p = 0; p < AEON; p++) {
      expect(tickIterateAeon(p)).toBe(p);
    }
  });

  test('phaseOfNatTick_succ aligns with tick', () => {
    for (let m = 0; m < 50; m++) {
      expect(phaseOfNatTick(m + 1)).toBe(tick(phaseOfNatTick(m)));
    }
  });

  test('minutesPerHourModAeonZero', () => {
    expect(minutesPerHourModAeonZero()).toBe(true);
  });

  test('phaseOfNatTick_addAeonMul', () => {
    for (let m = 0; m < 30; m++) {
      for (let k = 0; k < 8; k++) {
        expect(phaseOfNatTickAddAeonMul(m, k)).toBe(phaseOfNatTick(m));
      }
    }
  });

  test('phaseOfNatTick_addMinutesPerHourMul', () => {
    for (let m = 0; m < 25; m++) {
      for (let h = 0; h < 10; h++) {
        expect(phaseOfNatTickAddMinutesPerHourMul(m, h)).toBe(phaseOfNatTick(m));
      }
    }
  });

  test('invalid inputs throw', () => {
    expect(() => tick(-1)).toThrow(RangeError);
    expect(() => tick(12)).toThrow(RangeError);
    expect(() => tickIterate(0, 12)).toThrow(RangeError);
    expect(() => phaseOfNatTick(-3)).toThrow(RangeError);
    expect(() => tickIterate(-1, 0)).toThrow(RangeError);
  });

  test('MINUTES_PER_HOUR matches Circadian composition', () => {
    expect(MINUTES_PER_HOUR).toBe(60);
  });

  test('PHI satisfies φ · (φ − 1) = 1 at double precision', () => {
    expect(Math.abs(PHI * PHI_APERIODIC_ROTATION_STEP - 1)).toBeLessThan(1e-15);
  });

  test('tickPhiGated freezes θ when gate closed', () => {
    const s = phiRotationState(0.37);
    const closed = tickPhiGated(s, false);
    expect(closed.state.theta).toBe(s.theta);
    const closed2 = tickPhiGated(closed.state, false);
    expect(closed2.state.theta).toBe(s.theta);
  });

  test('tickPhiGated open advances θ by PHI_APERIODIC_ROTATION_STEP mod 1', () => {
    const s0 = phiRotationState(0.1);
    const a = tickPhiGated(s0, true);
    expect(a.state.theta).toBeCloseTo(
      normalizeUnitFrac(s0.theta + PHI_APERIODIC_ROTATION_STEP),
      14
    );
    expect(a.phase).toBe(phaseFromPhiTheta(a.state.theta));
  });

  test('tickPhi matches chained tickPhiGated(..., true)', () => {
    const s = phiRotationState(0);
    const once = tickPhi(s);
    const twice = tickPhi(once.state);
    let u = s;
    u = tickPhiGated(u, true).state;
    u = tickPhiGated(u, true).state;
    expect(twice.state.theta).toBeCloseTo(u.theta, 14);
  });

  test('phaseFromPhiTheta returns valid TimePhase for sample θ', () => {
    for (let i = 0; i < AEON; i++) {
      const th = (i + 0.5) / AEON;
      expect(phaseFromPhiTheta(th)).toBe(i);
    }
  });

  test('normalizeUnitFrac rejects non-finite', () => {
    expect(() => normalizeUnitFrac(Number.NaN)).toThrow(RangeError);
    expect(() => normalizeUnitFrac(Number.POSITIVE_INFINITY)).toThrow(RangeError);
  });
});
